public CreatureEditForm()          {              InitializeComponent();              LoadJSON();                Version version = System.Reflection.Assembly.GetExecutingAssembly().GetName().Version;              DateTime buildDate = new DateTime(2000, 1, 1)                                      .AddDays(version.Build).AddSeconds(version.Revision * 2);              string displayableVersion = $"{version} ({buildDate})";                            this.txtSplash.Text += string.Format("


Ver: {0}   Created by: RobG
",displayableVersion);              this.Shown += ShowForm;          }

